public server FWFTextBlockInstance copyToTarget(
    Common                 _target,
    boolean                _forceCopy = false
    )
{
    FWFTextBlockInstance   copyInstance;
    FWFTextBlockTransParm  sourceParm = this.transParm();
    FWFTextBlockTransParm  targetParm;

    if (sourceParm &&
        !_forceCopy &&
        !sourceParm.isValidForTarget(_target))
    {
        return copyInstance;
    }

    copyInstance.initValue();
    copyInstance.initFields(_target, this);

    // Instance for text block languages do not have transaction parameters
    if (sourceParm)
    {
        targetParm.data(sourceParm);
        if (targetParm.validateWrite())
        {
            targetParm.insert();
        }
        else
        {
            throw error(strFmt("@FWFTextBlock:ErrorValidationMsg", tableId2name(tableNum(FWFTextBlockTransParm)), funcName()));
        }

        copyInstance.SetupRecId = targetParm.RecId;
    }

    if (copyInstance.validateWrite())
    {
        copyInstance.insert();
    }
    else
    {
        throw error(strFmt("@FWFTextBlock:ErrorValidationMsg", tableId2name(tableNum(FWFTextBlockInstance)), funcName()));
    }

    return copyInstance;
}

public void delete()
{
    FWFTextblockValue value;
    PurchLine         purchLine;
    PurchTable        purchTable;
    AgreementLine     agreementLine;

    ttsBegin;

    if (! this.isSharingValue())
    {
        delete_from value
            where value.RecId == this.ValueRecId;
    }

    if (this.RefTableId == tableNum(PurchLine))
    {
        purchLine = PurchLine::findRecId(this.RefRecId);
        if (purchLine)
        {
            ttsbegin;
            purchLine.selectForUpdate(true);
            purchLine.IsModified = NoYes::Yes;
            purchLine.doUpdate();
            ttscommit;
        }

        purchTable = purchLine.purchTable(true);
        if (purchTable)
        {
            VersioningPurchaseOrder::newPurchaseOrder(purchTable).change(this, this.orig());
        }
    }

    if (this.RefTableId == tableNum(AgreementLine))
    {
        ttsbegin;
        agreementLine = AgreementLine::find(this.RefRecId, true);
        agreementLine.IsModified = NoYes::Yes;
        agreementLine.doUpdate();
        ttscommit;
    }

    super();

    ttsCommit;
}

public edit Notes editValue(boolean _set = false, Notes _text = '')
{
    FWFTextBlockValue    value, valueByHash;

    boolean              isSharingValue;

    if (_set)
    {
        ttsBegin;

        if (this.ValueRecId)
        {
            value = FWFTextBlockValue::find(this.ValueRecId, true);
        }

        if (value.TextBlock != _text)
        {
            if (value && _text)
            {
                isSharingValue = this.isSharingValue();

                if (! isSharingValue)
                {
                    if (_text)
                    {
                        valueByHash = FWFTextBlockValue::findByText(_text, true);
                    }

                    // Re-use existing text
                    if (valueByHash.RecId && valueByHash.RecId != value.RecId)
                    {
                        if (value.validateDelete())
                        {
                            value.delete();
                        }
                        else
                        {
                            throw error(strFmt("@FWFTextBlock:ErrorValidationMsg", tableId2name(tableNum(FWFTextBlockValue)), funcName()));
                        }

                        value.clear();
                        value.data(valueByHash);
                    }
                    // Change current text
                    else if (_text)
                    {
                        value.setText(_text);
                        if (value.validateWrite())
                        {
                            value.update();
                        }
                        else
                        {
                            throw error(strFmt("@FWFTextBlock:ErrorValidationMsg", tableId2name(tableNum(FWFTextBlockValue)), funcName()));
                        }

                    }
                    // Delete text
                    else if (! _text)
                    {
                        if (value.validateDelete())
                        {
                            value.delete();
                        }
                        else
                        {
                            throw error(strFmt("@FWFTextBlock:ErrorValidationMsg", tableId2name(tableNum(FWFTextBlockValue)), funcName()));
                        }
                        value.clear();
                    }
                }
            }
            if ((! value || isSharingValue) && _text)
            {
                value = FWFTextBlockValue::findOrCreate(_text);
            }
            else if (! _text)
            {
                value = null;
            }
        }

        this.ValueRecId = value.RecId;

        /*if (! this.ValueRecId)
        {
            // Not working for manually created texts in salesLine, etc.
            this.delete();
        }
        else */
        if (this.orig().ValueRecId != this.ValueRecId)
        {
            boolean doInsert = FWFTextBlockInstance::findRecId(this.RecId).RecId == 0;
            if (this.validateWrite())
            {
                if (doInsert)
                {
                    this.insert();
                }
                else
                {
                    this.update();
                }
            }
            else
            {
                throw error(strFmt("@FWFTextBlock:ErrorValidationMsg", tableId2name(tableNum(FWFTextBlockValue)), funcName()));
            }

        }
        if (FormDataUtil::isFormDataSource(this))
        {
            FormDataUtil::getFormDataSource(this).reread();
            FormDataUtil::getFormDataSource(this).refresh();
        }

        ttsCommit;

        return value.TextBlock;
    }

    return FWFTextBlockValue::find(this.ValueRecId).TextBlock;
}

public Counter getNextSortOrder()
{
    FWFTextBlockInstance  instance;
    FWFTextBlockTransParm transParm;

    select firstonly RefRecId from instance
        where instance.RefRecId        == this.RefRecId
           && instance.RefTableId      == this.RefTableId
    join maxOf(SortOrder) from transParm
        where transParm.RecId == instance.SetupRecId;

    return transParm.SortOrder + 1;
}

public str htmlText()
{
    FWFTextBlockValue value;

    select firstOnly TextBlock from value
        where value.RecId == this.ValueRecId;

    return value.htmlText();
}

public boolean isSharingValue()
{
    FWFTextBlockInstance otherInstances;

    select firstOnly RecId from otherInstances
        where otherInstances.ValueRecId == this.ValueRecId
          && otherInstances.RecId      != this.RecId;

    return otherInstances ? true : false;
}

public str plainText()
{
    str txt = this.editValue();

    txt = strReplace(txt, '<br>', '\n');
    //txt = strReplace(txt, '<p>', '\n');
    txt = System.Text.RegularExpressions.Regex::Replace(txt, '<.*?>', '');

    return txt;
}

public server static void copySourceToTarget(
    Common _source,
    Common _target,
    boolean _isIntercompany   = false,
    boolean _isDirectDelivery = false,
    boolean	_isRelatedPO	  = false)
{
    FWFTextBlockInstance   sourceInstance;
    FWFTextBlockInstance   targetInstance;

    while select sourceInstance
        where sourceInstance.RefTableId == _source.TableId
           && sourceInstance.RefRecId   == _source.RecId
    {
        if ((_isIntercompany && sourceInstance.transParm().ICCopy) ||
            (_isDirectDelivery && sourceInstance.transParm().DirectDeliveryCopy) ||
            (_isRelatedPO && sourceInstance.transParm().RelatedPOCopy))
        {
            select firstOnly RecId from targetInstance
                where targetInstance.RefTableId         == _target.TableId
                   && targetInstance.RefRecId           == _target.RecId
                   && targetInstance.ICInstanceRefRecId == sourceInstance.RecId;
            if (targetInstance)
            {
                continue;
            }

            targetInstance = sourceInstance.copyToTarget(_target, _isIntercompany);

            // add reference to source instance to avoid twice text block copying
            if (_isIntercompany)
            {
                targetInstance.ICInstanceRefRecId = sourceInstance.RecId;
                targetInstance.doUpdate();
            }
        }
        else if (!_isIntercompany	&&
                 !_isDirectDelivery &&
                 !_isRelatedPO)
        {
            sourceInstance.copyToTarget(_target, 0);
        }
    }
}

public server static void createFromSetupUsage(
    FWFTextBlockUsage     _usage,
    Common                _target,
    LanguageId            _languageId = '')
{
    FWFTextBlockLanguage  textBlockLanguage;
    FWFTextBlockInstance  sourceInstance, targetInstance;
    FWFTextBlockSetupParm sourceParm;
    FWFTextBlockTransParm targetTransParm;
    str                   textLine;
    container             textLines;
    int                   sortOrder, i;

    void findTextBlockLanguage()
    {
        select firstonly textBlockLanguage
            where textBlockLanguage.TextBlockRecId == _usage.TextBlockRecId
               && (textBlockLanguage.LanguageId    == _languageId || ! _languageId)
        join sourceInstance
            where sourceInstance.RefRecId   == textBlockLanguage.RecId
               && sourceInstance.RefTableId == textBlockLanguage.TableId
        // Don't add textblocks twice, e.g. from quotation and from setup
        notexists join targetInstance
            where targetInstance.RefRecId   == _target.RecId
               && targetInstance.RefTableId == _target.TableId
               && targetInstance.ValueRecId == sourceInstance.ValueRecId;
    }

    setPrefix(_usage.textBlockTable().Name);

    select sourceParm
        where sourceParm.RecId == _usage.SetupRefRefId;

    if (! sourceParm.isValidForTarget(_target, true))
    {
        return;
    }

    ttsBegin;

    findTextBlockLanguage();

    if(! textBlockLanguage && sourceParm.ShowWarning && _languageId)	// show warning regardless of language
    {
        _languageId = '';
        findTextBlockLanguage();
    }

    if (textBlockLanguage)
    {
        targetInstance = sourceInstance.copyToTarget(_target);
        sortOrder      = targetInstance.getNextSortOrder();

        targetTransParm.initFromSetupParm(sourceParm);
        targetTransParm.initFromPurchSalesAgreement(_target);

        targetTransParm.LanguageId   = _languageId ? _languageId : textBlockLanguage.LanguageId;
        targetTransParm.Name         = textBlockLanguage.textBlockTable().Name;
        targetTransParm.SortOrder    = sortOrder >= targetTransParm.SortOrder ? sortOrder : targetTransParm.SortOrder + 1;
        if (targetTransParm.validateWrite())
        {
            targetTransParm.insert();
        }
        else
        {
            throw error(strFmt("@FWFTextBlock:ErrorValidationMsg", tableId2name(tableNum(FWFTextBlockTransParm)), funcName()));
        }

        targetInstance.setupRecId = targetTransParm.RecId;
        if (targetInstance.validateWrite())
        {
            targetInstance.update();
        }
        else
        {
            throw error(strFmt("@FWFTextBlock:ErrorValidationMsg", tableId2name(tableNum(FWFTextBlockTransParm)), funcName()));
        }

        if (targetTransParm.ShowWarning)
        {
            textLines = str2con(FWFTextBlockValueSubstitutor::newParameters(_target, _target, targetInstance.plainText()).run(), '\n');
            for (i=1; i<=conLen(textLines); i++)
            {
                textLine = conPeek(textLines, i);
                if (textLine)
                {
                    warning(textLine);
                }
            }
        }
    }

    ttsCommit;
}

/// <summary>
/// Finds a <c>FWFTextBlockInstance</c> record.
/// </summary>
/// <param name = "_recId">The <c>RecId</c> value to search for.</param>
/// <param name = "_forUpdate">A Boolean value; TRUE, if the record should be selected forupdate, otherwise FALSE.</param>
/// <returns>The found <c>FWFTextBlockInstance</c> record.</returns>
public static FWFTextBlockInstance findRecId(RecId _recId, boolean _forUpdate = false)
{
    FWFTextBlockInstance textBlockInstance;

    if (_forUpdate)
    {
        textBlockInstance.selectForUpdate(_forUpdate);
    }

    if (_recId)
    {
        select firstonly textBlockInstance
            where textBlockInstance.RecId == _recId;
    }

    return textBlockInstance;
}

public static FWFTextBlockInstance find(RecId _refRecId, TableId _refTableId, boolean _forUpdate = false)
{
    FWFTextBlockInstance textBlockInstance;

    if (_forUpdate)
    {
        textBlockInstance.selectForUpdate(_forUpdate);
    }

    if (_refRecId && _refTableId)
    {
        select firstonly textBlockInstance
            where textBlockInstance.RefRecId   == _refRecId
               && textBlockInstance.RefTableId == _refTableId;
    }

    return textBlockInstance;
}

    /// <summary>
    ///
    /// </summary>
    public static boolean hasTextBlock(Common	_common)
    {
        boolean					ret = false;
        FWFTextBlockInstance	instance;
        TableId					tableId = _common.TableId;

        if (_common.TableId == tableNum(AgreementLineQuantityCommitment) ||
            _common.TableId == tableNum(AgreementLineVolumeCommitment))
        {
            tableId = tableNum(AgreementLine);
        }

        /*
        if (_common.TableId == tableNum(AgreementLineQuantityCommitmentHistory) ||
            _common.TableId == tableNum(AgreementLineVolumeCommitmentHistory))
        {
            tableId = tableNum(AgreementLineHistory);
        }
        */

        if (_common.TableId == tableNum(PurchLineAllVersions))
        {
            PurchLineAllVersions	purchLineAllVersions = _common;
            if (purchLineAllVersions.IsArchived)	// if already archived, the textblocks are referenced to the PurchLineHistory
            {
				tableId = tableNum(PurchLineHistory);
            }
        }

        select firstonly instance
            where instance.RefTableId == tableId
               && instance.RefRecId   == _common.RecId;

        if (instance)
        {
            ret = true;
        }

        return ret;
    }

public void initFields(Common _target, FWFTextBlockInstance _instance)
{
    this.RefTableId = _target.TableId;
    this.RefRecId   = _target.RecId;
    this.ValueRecId = _instance.ValueRecId;
}

/// <summary>
///
/// </summary>
public void update()
{
    PurchLine       purchLine;
    PurchTable      purchTable;
    AgreementLine   agreementLine;

    if (this.RefTableId == tableNum(PurchLine))
    {
        if (this.ValueRecId != this.orig().ValueRecId)
        {
            ttsbegin;
            purchLine = PurchLine::findRecId(this.RefRecId, true);
            purchLine.IsModified = NoYes::Yes;
            purchLine.doUpdate();
            ttscommit;

            purchTable = purchLine.purchTable(true);
            if (purchTable)
            {
                VersioningPurchaseOrder::newPurchaseOrder(purchTable).change(this, this.orig());
            }
        }
    }

    if (this.RefTableId == tableNum(AgreementLine))
    {
        ttsbegin;
        agreementLine = AgreementLine::find(this.RefRecId, true);
        agreementLine.IsModified = NoYes::Yes;
        agreementLine.doUpdate();
        ttscommit;
    }

    super();
}

static void updateCallerDatasource(Common _common)
{
    Object  dataSource;

    if (_common.TableId == tableNum(PurchLine) || _common.TableId == tableNum(AgreementLine))
    {
        if ( FormDataUtil::isFormDataSource(_common))
        {
            dataSource = FormDataUtil::getFormDataSource(_common);

            if (dataSource)
            {
                dataSource.reread();
            }
        }
    }
}

/// <summary>
///
/// </summary>
public void insert()
{
    PurchLine       purchLine;
    PurchTable      purchTable;
    AgreementLine   agreementLine;

    if (this.RefTableId == tableNum(PurchLine))
    {
        ttsbegin;
        purchLine = PurchLine::findRecId(this.RefRecId, true);
        purchLine.IsModified = NoYes::Yes;
        purchLine.doUpdate();
        ttscommit;

        purchTable = purchLine.purchTable(true);
        if (purchTable)
        {
            VersioningPurchaseOrder::newPurchaseOrder(purchTable).change(this, this.orig());
        }
    }

    if (this.RefTableId == tableNum(AgreementLine))
    {
        ttsbegin;
        agreementLine = AgreementLine::find(this.RefRecId, true);
        agreementLine.IsModified = NoYes::Yes;
        agreementLine.doUpdate();
        ttscommit;
    }

    super();
}
